parameters.jsCode:
const gadsRaw = $input.first().json;
const alerts = [];
const rows = [];
const batches = Array.isArray(gadsRaw) ? gadsRaw : [gadsRaw];
for (const batch of batches) { if (batch.results) rows.push(...batch.results); }

const campaignMap = {};
for (const row of rows) {
  const id = row.campaign?.id || 'unknown';
  if (!campaignMap[id]) { campaignMap[id] = { name: row.campaign?.name || 'Unknown', id, costMicros: 0, clicks: 0, impressions: 0, conversions: 0, searchImprShare: 0, rowCount: 0 }; }
  const m = row.metrics || {};
  campaignMap[id].costMicros += parseInt(m.costMicros || 0);
  campaignMap[id].clicks += parseInt(m.clicks || 0);
  campaignMap[id].impressions += parseInt(m.impressions || 0);
  campaignMap[id].conversions += parseFloat(m.conversions || 0);
  campaignMap[id].searchImprShare += parseFloat(m.searchImpressionShare || 0);
  campaignMap[id].rowCount += 1;
}

const campaigns = Object.values(campaignMap).map(c => ({
  ...c, spend: c.costMicros / 1000000,
  cpa: c.conversions > 0 ? c.costMicros / 1000000 / c.conversions : null,
  ctr: c.impressions > 0 ? c.clicks / c.impressions * 100 : 0,
  avgImprShare: c.rowCount > 0 ? c.searchImprShare / c.rowCount : 0
}));

for (const c of campaigns) {
  if (c.spend > 30 && c.conversions === 0) alerts.push({ rule: 'PAUSAR', campaign: c.name, metric: `USD ${c.spend.toFixed(2)}, 0 conv`, rec: `"${c.name}" gasto USD ${c.spend.toFixed(2)} en 7 dias sin conversiones. Considerar pausar.` });
  if (c.cpa !== null && c.cpa < 15 && c.conversions >= 5) alerts.push({ rule: 'ESCALAR', campaign: c.name, metric: `CPA USD ${c.cpa.toFixed(2)}, ${c.conversions} conv`, rec: `"${c.name}" tiene CPA bajo (USD ${c.cpa.toFixed(2)}) con ${c.conversions} conversiones. Aumentar budget 15%.` });
  if (c.avgImprShare < 0.5 && c.conversions > 0) alerts.push({ rule: 'BID', campaign: c.name, metric: `Impr Share ${(c.avgImprShare * 100).toFixed(1)}%`, rec: `"${c.name}" tiene impression share bajo (${(c.avgImprShare * 100).toFixed(1)}%) pero convierte. Aumentar bid.` });
  if (c.ctr < 1 && c.impressions > 100) alerts.push({ rule: 'COPY', campaign: c.name, metric: `CTR ${c.ctr.toFixed(2)}%`, rec: `"${c.name}" tiene CTR bajo (${c.ctr.toFixed(2)}%). Revisar copy de anuncios.` });
}

return [{ json: { alerts, hasAlerts: alerts.length > 0, count: campaigns.length } }];

const data = $input.first().json;
const alerts = data.alerts || [];
let msg = '*Google Ads Optimizer*\n';
msg += `Campanas: ${data.count} | Alertas: ${alerts.length}\n\n`;
for (const a of alerts) { msg += `[${a.rule}] ${a.rec}\n\n`; }
msg += 'Nota: Google Ads no se modifica automaticamente. Aplicar manualmente.';
return [{ json: { message: msg } }];
